#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long n;
        scanf("%lld", &n);
        if (n == 0) break;
        if ((log(n) / log(3)) == (long long)(log(n) / log(3))) {
            printf("L\n");
        } else {
            long long i = 1;
            while (i * 3 <= n) i *= 3;
            printf("%lld\n", n - i);
        }
    }
    return 0;
}

