import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long n = sc.nextLong();
            if (n == 0) break;
            if (Math.log(n) / Math.log(3) == (long)(Math.log(n) / Math.log(3))) {
                System.out.println("L");
            } else {
                long i = 1;
                while (i * 3 <= n) i *= 3;
                System.out.println(n - i);
            }
        }
    }
}

